#include<bits/stdc++.h>
using namespace std;
string s;
int main()
{
	while(1){
		char c;
		cin >> c;
		if(c == 'E')break;
		if(c == 'W' || c == 'L') s += c;
	}
	int hua = 0, dui = 0;
	for(int i = 0; i < s.size(); i++){
		if(s[i] == 'L')dui++;
		else if(s[i] == 'W')hua++;
		if((hua >= 11 || dui >= 11) && abs(hua - dui) >= 2){
			cout << hua << ":" << dui << endl;
			hua = 0;
			dui = 0;
		}
	}
	cout << hua << ":" << dui << endl;

	cout << endl;

	hua = 0, dui = 0;  // 重置变量
	for(int i = 0; i < s.size(); i++){
		if(s[i] == 'L')dui++;
		else if(s[i] == 'W')hua++;
		if((hua >= 21 || dui >= 21) && abs(hua - dui) >= 2){
			cout << hua << ":" << dui << endl;
			hua = 0;
			dui = 0;
		}
	}
	cout << hua << ":" << dui << endl;
}
